// Setup Date Context
const now = new Date();
const eastern = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
const year = eastern.getFullYear();
const month = String(eastern.getMonth() + 1).padStart(2, '0');
const day = String(eastern.getDate()).padStart(2, '0');
const currentDate = `${year}-${month}-${day}`;

const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
const dateFormatted = `${months[eastern.getMonth()]} ${eastern.getDate()}, ${year}`;

const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
const currentDay = days[eastern.getDay()];
const isWeekend = eastern.getDay() === 0 || eastern.getDay() === 6;

const prev = new Date(eastern);
prev.setDate(prev.getDate() - 1);
const prevYear = prev.getFullYear();
const prevMonth = String(prev.getMonth() + 1).padStart(2, '0');
const prevDay = String(prev.getDate()).padStart(2, '0');
const previousDate = `${prevYear}-${prevMonth}-${prevDay}`;

const vaultPath = '/data/obsidian-vault';
const digestDir = vaultPath + '/Email Digests';

return [{
  json: {
    currentDate,
    dateFormatted,
    currentDay,
    isWeekend,
    previousDate,
    vaultPath,
    digestDir,
    digestPath: digestDir + '/' + currentDate + '.md',
    actionItemsPath: digestDir + '/action-items.md',
    ongoingThreadsPath: digestDir + '/ongoing-threads.md',
    lastRunPath: digestDir + '/.last-run.txt'
  }
}];

const fs = require('fs');
const digestPath = $json.digestPath;
try {
  if (fs.existsSync(digestPath)) {
    const content = fs.readFileSync(digestPath, 'utf8');
    return [{ json: { data: content, exists: true } }];
  }
} catch (e) {}
return [{ json: { data: null, exists: false } }];

const fs = require('fs');
const dateCtx = $('Setup Date Context').first().json;
const vaultPath = dateCtx.vaultPath;
const digestDir = dateCtx.digestDir;
const previousDate = dateCtx.previousDate;

function readFile(p) { try { return fs.existsSync(p) ? fs.readFileSync(p, 'utf8') : ''; } catch(e) { return ''; } }

const lastRunRaw = readFile(digestDir + '/.last-run.txt');
let lastRunTimestamp = lastRunRaw.trim();
if (!lastRunTimestamp || lastRunTimestamp.length < 10) {
  const fb = new Date(Date.now() - 18*60*60*1000);
  lastRunTimestamp = fb.toISOString();
}

const actionItemsRaw = readFile(digestDir + '/action-items.md');
const prevDigestRaw = readFile(digestDir + '/' + previousDate + '.md');
const threadsRaw = readFile(digestDir + '/ongoing-threads.md');

let previousDigestSummary = '';
const sumMatch = prevDigestRaw.match(/## Executive Summary\n\n([\s\S]*?)\n\n---/);
if (sumMatch) previousDigestSummary = sumMatch[1].trim();

return [{ json: {
  lastRunTimestamp,
  actionItems: actionItemsRaw,
  previousDigestSummary,
  ongoingThreads: threadsRaw
}}];

// Gmail fetch - returns empty until OAuth is configured via env vars
// To enable: set GMAIL_ACCESS_TOKEN env var
const token = $env.GMAIL_ACCESS_TOKEN || '';
if (!token) {
  return [{ json: { emails: [], count: 0, error: 'GMAIL_ACCESS_TOKEN not set' } }];
}
try {
  const lastRun = $json.lastRunTimestamp || '';
  const after = lastRun ? lastRun.split('T')[0].replace(/-/g, '/') : '';
  const q = encodeURIComponent('after:' + after + ' -from:me -in:drafts');
  const resp = await fetch('https://gmail.googleapis.com/gmail/v1/users/me/messages?maxResults=50&q=' + q, {
    headers: { 'Authorization': 'Bearer ' + token }
  });
  const data = await resp.json();
  return [{ json: { emails: data.messages || [], count: (data.messages || []).length } }];
} catch(e) {
  return [{ json: { emails: [], count: 0, error: e.message } }];
}

// Outlook fetch - returns empty until OAuth is configured
const token = $env.OUTLOOK_ACCESS_TOKEN || '';
if (!token) {
  return [{ json: { emails: [], count: 0, error: 'OUTLOOK_ACCESS_TOKEN not set' } }];
}
try {
  const lastRun = $json.lastRunTimestamp || '';
  const filter = lastRun ? "&$filter=receivedDateTime ge " + lastRun : "";
  const resp = await fetch('https://graph.microsoft.com/v1.0/me/mailFolders/inbox/messages?$top=50' + filter, {
    headers: { 'Authorization': 'Bearer ' + token }
  });
  const data = await resp.json();
  return [{ json: { emails: data.value || [], count: (data.value || []).length } }];
} catch(e) {
  return [{ json: { emails: [], count: 0, error: e.message } }];
}

// Merge All Data from parallel sub-workflow calls
// Gmail results come from 'Fetch Gmail' node
// Outlook results come from 'Fetch Outlook' node
// Calendar results come from 'Fetch Calendar' node
// Context comes from 'Fetch Obsidian Context' node

let gmailEmails = [];
let outlookEmails = [];
let calendarEvents = [];
let obsidianContext = {};

// Get Gmail emails
try {
  const gmailData = $('Fetch Gmail').all();
  if (gmailData && gmailData.length > 0) {
    const firstItem = gmailData[0].json;
    if (firstItem.emails && Array.isArray(firstItem.emails)) {
      gmailEmails = firstItem.emails;
    } else if (Array.isArray(firstItem)) {
      gmailEmails = firstItem;
    }
  }
} catch (e) {
  // Gmail fetch failed — continue with empty
}

// Get Outlook emails
try {
  const outlookData = $('Fetch Outlook').all();
  if (outlookData && outlookData.length > 0) {
    const firstItem = outlookData[0].json;
    if (firstItem.emails && Array.isArray(firstItem.emails)) {
      outlookEmails = firstItem.emails;
    } else if (Array.isArray(firstItem)) {
      outlookEmails = firstItem;
    }
  }
} catch (e) {
  // Outlook fetch failed — continue with empty
}

// Get Calendar events
try {
  const calData = $('Fetch Calendar').all();
  if (calData && calData.length > 0) {
    const firstItem = calData[0].json;
    if (firstItem.events && Array.isArray(firstItem.events)) {
      calendarEvents = firstItem.events;
    } else if (Array.isArray(firstItem)) {
      calendarEvents = firstItem;
    }
  }
} catch (e) {
  // Calendar fetch failed — continue with empty
}

// Get Obsidian context
try {
  const contextData = $('Fetch Obsidian Context').all();
  if (contextData && contextData.length > 0) {
    obsidianContext = contextData[0].json || {};
  }
} catch (e) {
  // Context reader failed — continue without context
}

// Merge all emails into a single array
const allEmails = [...gmailEmails, ...outlookEmails];

// Get date context from Setup Date Context node
const dateContext = $('Setup Date Context').first().json;

return [{
  json: {
    emails: allEmails,
    gmailCount: gmailEmails.length,
    outlookCount: outlookEmails.length,
    totalEmails: allEmails.length,
    calendarEvents,
    previousActionItems: obsidianContext.actionItems || '',
    previousDigestSummary: obsidianContext.previousDigestSummary || '',
    ongoingThreads: obsidianContext.ongoingThreads || '',
    lastRunTimestamp: obsidianContext.lastRunTimestamp || '',
    currentDate: dateContext.currentDate,
    dateFormatted: dateContext.dateFormatted,
    currentDay: dateContext.currentDay,
    isWeekend: dateContext.isWeekend,
    previousDate: dateContext.previousDate,
    vaultPath: dateContext.vaultPath,
    digestDir: dateContext.digestDir,
    digestPath: dateContext.digestPath,
    actionItemsPath: dateContext.actionItemsPath,
    ongoingThreadsPath: dateContext.ongoingThreadsPath,
    lastRunPath: dateContext.lastRunPath
  }
}];

// Prepare AI Payload — build Claude API request body
const data = $json;

const systemPrompt = `You are a senior executive assistant and intelligence analyst for Aryan Singh, a student at Johns Hopkins University. Your job is to analyze his email inbox and produce a comprehensive daily intelligence briefing.

## Your Analysis Tasks

For each email, produce:
1. A detailed 2-3 sentence summary (not just the subject line — what does this email actually say and why does it matter?)
2. An importance score from 1-10 using this weighting:
   - Content urgency (50%): deadlines, time-sensitive requests, consequences of inaction
   - Sender significance (25%): professors, employers, family > newsletters, automated notifications
   - Category weight (25%): school/career > personal > social > newsletters
3. Specific, actionable tasks extracted from the email (not vague — "Reply to Prof. Smith with revised proposal by Friday 5pm" not "follow up")
4. Calendar cross-references: if any email relates to today's or tomorrow's calendar events, explain the connection and what to prepare
5. Thread context: if this is part of an ongoing conversation, summarize the thread history
6. Key information: extract specific facts, dates, dollar amounts, links, names worth noting
7. Suggested response: if a reply is needed, provide talking points

## Importance Scoring Guide
- 9-10: Immediate action required, serious consequences if missed (deadline today, urgent from professor/employer)
- 7-8: Important, should handle today (upcoming deadline, significant request, career opportunity)
- 5-6: Moderate, handle this week (informational from important sender, non-urgent request)
- 3-4: Low priority (newsletters with useful content, FYI notifications)
- 1-2: Noise (marketing, social media notifications, spam that got through)

## Weekend Mode
When the weekend flag is true:
- Raise the threshold for "Priority Emails" to 8+ (vs 7+ on weekdays)
- Suppress newsletters and social notifications from the executive summary
- Still track all action items regardless

## Continuity
You will receive:
- Previous day's unresolved action items — flag which are still relevant, which may be resolved by new emails
- Previous day's digest summary — reference it for comparison stats
- Ongoing thread summaries — note any threads that progressed overnight

## Output Format
Respond with valid JSON matching this schema. No markdown wrapping, no explanation — just the JSON object.

{
  "executiveSummary": "3-5 sentence overview of inbox state",
  "emailAnalyses": [
    {
      "emailId": "string",
      "summary": "2-3 sentence detailed summary",
      "importanceScore": 1-10,
      "importanceReason": "specific reason",
      "category": "school|personal|newsletter|transactional|social|financial|career",
      "sentiment": "positive|neutral|negative|urgent",
      "actionItems": [
        {
          "task": "specific actionable task",
          "deadline": "ISO datetime or null",
          "effort": "quick|medium|deep-work",
          "priority": "must-do-today|this-week|when-possible",
          "context": "why this matters"
        }
      ],
      "calendarRelevance": { "relatedEvent": "string", "connection": "string" } or null,
      "threadContext": "string or null",
      "keyInfo": ["extracted facts", "dates", "links"],
      "suggestedResponse": "string or null"
    }
  ],
  "consolidatedActionItems": [
    {
      "task": "string",
      "deadline": "string or null",
      "effort": "quick|medium|deep-work",
      "priority": "must-do-today|this-week|when-possible",
      "context": "string",
      "sourceEmail": "subject line"
    }
  ],
  "ongoingThreads": [
    {
      "threadId": "string",
      "subject": "string",
      "participants": ["string"],
      "lastActivity": "ISO date",
      "summary": "string"
    }
  ],
  "staleItems": [
    {
      "task": "string",
      "originalDate": "YYYY-MM-DD",
      "daysStale": 3,
      "recommendation": "string"
    }
  ],
  "inboxStats": {
    "total": 0,
    "bySource": { "gmail": 0, "outlook": 0 },
    "byCategory": {},
    "comparisonToYesterday": "string",
    "unreadRemaining": 0
  }
}`;

const userMessage = JSON.stringify({
  emails: data.emails,
  calendarEvents: data.calendarEvents,
  previousActionItems: data.previousActionItems,
  previousDigestSummary: data.previousDigestSummary,
  currentDate: data.currentDate,
  currentDay: data.currentDay,
  isWeekend: data.isWeekend
});

const model = process.env.N8N_CLAUDE_MODEL || 'claude-sonnet-4-6-20250514';

const requestBody = {
  model,
  max_tokens: 4096,
  system: systemPrompt,
  messages: [
    {
      role: 'user',
      content: userMessage
    }
  ]
};

return [{
  json: {
    requestBody,
    ...data
  }
}];

const apiKey = $env.ANTHROPIC_API_KEY || '';
if (!apiKey) {
  return [{ json: { statusCode: 401, body: { error: 'ANTHROPIC_API_KEY not set' } } }];
}
try {
  const resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: JSON.stringify($json.requestBody)
  });
  const body = await resp.json();
  return [{ json: { statusCode: resp.status, body } }];
} catch(e) {
  return [{ json: { statusCode: 500, body: { error: e.message } } }];
}

// Prepare OpenAI Fallback — reformat the payload for OpenAI API
const data = $('Prepare AI Payload').first().json;
const claudeBody = data.requestBody;

const openAIBody = {
  model: process.env.N8N_OPENAI_MODEL || 'gpt-4o',
  max_tokens: 4096,
  messages: [
    {
      role: 'system',
      content: claudeBody.system
    },
    {
      role: 'user',
      content: claudeBody.messages[0].content
    }
  ],
  temperature: 0.3
};

return [{
  json: {
    openAIBody,
    currentDate: data.currentDate,
    dateFormatted: data.dateFormatted,
    currentDay: data.currentDay,
    isWeekend: data.isWeekend,
    previousDate: data.previousDate,
    vaultPath: data.vaultPath,
    digestDir: data.digestDir,
    digestPath: data.digestPath,
    actionItemsPath: data.actionItemsPath,
    ongoingThreadsPath: data.ongoingThreadsPath,
    lastRunPath: data.lastRunPath,
    totalEmails: data.totalEmails,
    gmailCount: data.gmailCount,
    outlookCount: data.outlookCount,
    emails: data.emails,
    calendarEvents: data.calendarEvents,
    previousActionItems: data.previousActionItems,
    aiProvider: 'openai'
  }
}];

const apiKey = $env.OPENAI_API_KEY || '';
if (!apiKey) {
  return [{ json: { statusCode: 401, body: { error: 'OPENAI_API_KEY not set' } } }];
}
try {
  const resp = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'content-type': 'application/json'
    },
    body: JSON.stringify($json.openAIBody)
  });
  const body = await resp.json();
  return [{ json: { statusCode: resp.status, body } }];
} catch(e) {
  return [{ json: { statusCode: 500, body: { error: e.message } } }];
}

// Prepare Gemini Fallback — reformat the payload for Google Gemini API
const data = $('Prepare AI Payload').first().json;
const claudeBody = data.requestBody;

const geminiModel = process.env.N8N_GEMINI_MODEL || 'gemini-2.0-flash';
const geminiApiKey = process.env.N8N_GEMINI_API_KEY || '';

const geminiBody = {
  contents: [
    {
      role: 'user',
      parts: [
        {
          text: claudeBody.system + '\n\n---\n\n' + claudeBody.messages[0].content
        }
      ]
    }
  ],
  generationConfig: {
    maxOutputTokens: 4096,
    temperature: 0.3
  }
};

return [{
  json: {
    geminiBody,
    geminiUrl: `https://generativelanguage.googleapis.com/v1beta/models/${geminiModel}:generateContent?key=${geminiApiKey}`,
    currentDate: data.currentDate,
    dateFormatted: data.dateFormatted,
    currentDay: data.currentDay,
    isWeekend: data.isWeekend,
    previousDate: data.previousDate,
    vaultPath: data.vaultPath,
    digestDir: data.digestDir,
    digestPath: data.digestPath,
    actionItemsPath: data.actionItemsPath,
    ongoingThreadsPath: data.ongoingThreadsPath,
    lastRunPath: data.lastRunPath,
    totalEmails: data.totalEmails,
    gmailCount: data.gmailCount,
    outlookCount: data.outlookCount,
    emails: data.emails,
    calendarEvents: data.calendarEvents,
    previousActionItems: data.previousActionItems,
    aiProvider: 'gemini'
  }
}];

const apiKey = $env.GEMINI_API_KEY || '';
if (!apiKey) {
  return [{ json: { statusCode: 401, body: { error: 'GEMINI_API_KEY not set' } } }];
}
try {
  const url = $json.geminiUrl || ('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=' + apiKey);
  const resp = await fetch(url, {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify($json.geminiBody)
  });
  const body = await resp.json();
  return [{ json: { statusCode: resp.status, body } }];
} catch(e) {
  return [{ json: { statusCode: 500, body: { error: e.message } } }];
}

const slackToken = $env.SLACK_BOT_TOKEN || '';
const channel = $env.SLACK_CHANNEL || '#morning-briefing';
if (!slackToken) {
  console.log('SLACK_BOT_TOKEN not set - skipping failure alert');
  return [{ json: { ok: false, error: 'SLACK_BOT_TOKEN not set' } }];
}
try {
  const resp = await fetch('https://slack.com/api/chat.postMessage', {
    method: 'POST',
    headers: { 'Authorization': 'Bearer ' + slackToken, 'content-type': 'application/json' },
    body: JSON.stringify({ channel, text: 'All AI providers failed for the morning briefing. Manual review required.' })
  });
  return [{ json: await resp.json() }];
} catch(e) {
  return [{ json: { ok: false, error: e.message } }];
}

// Parse AI Response — handles Claude, OpenAI, and Gemini response formats
// This node receives output from whichever AI provider succeeded

let rawText = '';
let aiProvider = 'unknown';

// Try to determine which provider responded
// Check if we have a Claude response (from Claude API node directly via true branch)
try {
  const claudeResponse = $('Claude API').first().json;
  if (claudeResponse && claudeResponse.statusCode === 200) {
    // Claude format: { body: { content: [{ type: 'text', text: '...' }] } }
    const body = typeof claudeResponse.body === 'string' ? JSON.parse(claudeResponse.body) : claudeResponse.body;
    if (body && body.content && body.content[0]) {
      rawText = body.content[0].text;
      aiProvider = 'claude';
    }
  }
} catch (e) { /* not Claude */ }

// Check OpenAI response
if (!rawText) {
  try {
    const openaiResponse = $('OpenAI API').first().json;
    if (openaiResponse && openaiResponse.statusCode === 200) {
      const body = typeof openaiResponse.body === 'string' ? JSON.parse(openaiResponse.body) : openaiResponse.body;
      if (body && body.choices && body.choices[0]) {
        rawText = body.choices[0].message.content;
        aiProvider = 'openai';
      }
    }
  } catch (e) { /* not OpenAI */ }
}

// Check Gemini response
if (!rawText) {
  try {
    const geminiResponse = $('Gemini API').first().json;
    if (geminiResponse && geminiResponse.statusCode === 200) {
      const body = typeof geminiResponse.body === 'string' ? JSON.parse(geminiResponse.body) : geminiResponse.body;
      if (body && body.candidates && body.candidates[0]) {
        rawText = body.candidates[0].content.parts[0].text;
        aiProvider = 'gemini';
      }
    }
  } catch (e) { /* not Gemini */ }
}

// Clean up the response — strip markdown code fences if present
rawText = rawText.trim();
if (rawText.startsWith('```json')) {
  rawText = rawText.slice(7);
}
if (rawText.startsWith('```')) {
  rawText = rawText.slice(3);
}
if (rawText.endsWith('```')) {
  rawText = rawText.slice(0, -3);
}
rawText = rawText.trim();

// Parse JSON
let analysis;
try {
  analysis = JSON.parse(rawText);
} catch (e) {
  // Try to extract JSON from the response
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('Failed to parse AI response as JSON: ' + rawText.substring(0, 200));
  }
}

// Carry forward all context data
const mergedData = $('Merge All Data').first().json;

return [{
  json: {
    analysis,
    aiProvider,
    currentDate: mergedData.currentDate,
    dateFormatted: mergedData.dateFormatted,
    currentDay: mergedData.currentDay,
    isWeekend: mergedData.isWeekend,
    previousDate: mergedData.previousDate,
    vaultPath: mergedData.vaultPath,
    digestDir: mergedData.digestDir,
    digestPath: mergedData.digestPath,
    actionItemsPath: mergedData.actionItemsPath,
    ongoingThreadsPath: mergedData.ongoingThreadsPath,
    lastRunPath: mergedData.lastRunPath,
    totalEmails: mergedData.totalEmails,
    gmailCount: mergedData.gmailCount,
    outlookCount: mergedData.outlookCount,
    emails: mergedData.emails,
    calendarEvents: mergedData.calendarEvents,
    previousActionItems: mergedData.previousActionItems
  }
}];

// Build Obsidian Digest — full markdown with YAML frontmatter and all 7 sections
const data = $json;
const a = data.analysis;
const threshold = data.isWeekend ? 8 : 7;

// Determine urgency level
const urgentCount = (a.consolidatedActionItems || []).filter(i => i.priority === 'must-do-today').length;
let urgencyLevel = 'low';
if (urgentCount >= 3) urgencyLevel = 'high';
else if (urgentCount >= 1) urgencyLevel = 'medium';

// YAML frontmatter
let md = `---\ndate: "${data.currentDate}"\ntotal_emails: ${data.totalEmails}\nurgency_level: "${urgencyLevel}"\ntags: [email-digest, "${data.currentDate}"]\n---\n\n`;

// Title
md += `# Daily Intelligence Briefing — ${data.dateFormatted}\n\n`;
md += `> Previous: [[${data.previousDate}]]\n\n`;

// Section 1: Executive Summary
md += `## Executive Summary\n\n${a.executiveSummary || 'No summary available.'}\n\n---\n\n`;

// Section 2: Calendar + Email Cross-Reference
md += `## Today's Calendar + Email Cross-Reference\n\n`;
if (data.calendarEvents && data.calendarEvents.length > 0) {
  data.calendarEvents.forEach(evt => {
    const startTime = evt.startTime || evt.start || '';
    const endTime = evt.endTime || evt.end || '';
    md += `- **${startTime} — ${endTime}**: ${evt.summary || evt.title || 'Untitled'}\n`;
    if (evt.location) md += `  - Location: ${evt.location}\n`;
  });
  md += '\n';
  // Cross-references from email analyses
  const crossRefs = (a.emailAnalyses || []).filter(e => e.calendarRelevance);
  if (crossRefs.length > 0) {
    md += '**Email-Calendar Connections:**\n';
    crossRefs.forEach(e => {
      md += `- ${e.calendarRelevance.relatedEvent}: ${e.calendarRelevance.connection}\n`;
    });
  }
} else {
  md += 'No calendar events today.\n';
}
md += '\n---\n\n';

// Section 3: Action Items Dashboard
md += `## Action Items Dashboard\n\n`;
md += `| Priority | Action | Source | Deadline | Effort | Context |\n`;
md += `|----------|--------|--------|----------|--------|---------|\n`;
const actionItems = a.consolidatedActionItems || [];
if (actionItems.length > 0) {
  actionItems.forEach(item => {
    const priority = item.priority || 'when-possible';
    const task = (item.task || '').replace(/\|/g, '/');
    const source = (item.sourceEmail || '').replace(/\|/g, '/');
    const deadline = item.deadline || '—';
    const effort = item.effort || '—';
    const context = (item.context || '').replace(/\|/g, '/').substring(0, 60);
    md += `| ${priority} | ${task} | ${source} | ${deadline} | ${effort} | ${context} |\n`;
  });
} else {
  md += '| — | No action items today | — | — | — | — |\n';
}
md += '\n---\n\n';

// Section 4: Priority Emails
md += `## Priority Emails\n\n`;
const priorityEmails = (a.emailAnalyses || []).filter(e => e.importanceScore >= threshold);
if (priorityEmails.length > 0) {
  priorityEmails.sort((a, b) => b.importanceScore - a.importanceScore);
  priorityEmails.forEach(e => {
    // Find original email for metadata
    const original = (data.emails || []).find(orig => orig.id === e.emailId) || {};
    md += `### ${original.subject || e.emailId} (Score: ${e.importanceScore}/10)\n\n`;
    md += `**From:** ${original.from ? (original.from.name || original.from.email) : 'Unknown'} | `;
    md += `**Source:** ${original.source || 'unknown'} | `;
    md += `**Category:** ${e.category} | **Sentiment:** ${e.sentiment}\n\n`;
    md += `${e.summary}\n\n`;
    if (e.importanceReason) md += `**Why it matters:** ${e.importanceReason}\n\n`;
