// Build Action Items MD — rebuild action-items.md with new + previous unresolved items
const data = $json;
const a = data.analysis;
const currentDate = data.currentDate;

// Parse previous action items from markdown
const previousRaw = data.previousActionItems || '';
let previousItems = [];

// Extract tasks from previous markdown (lines matching: - [ ] or - [x])
const lines = previousRaw.split('\n');
lines.forEach(line => {
  const uncheckedMatch = line.match(/^\s*-\s*\[\s*\]\s*(.+)$/);
  const checkedMatch = line.match(/^\s*-\s*\[x\]\s*~~?(.+?)~~?(?:\s*—\s*Completed\s*(.+))?$/i);
  if (uncheckedMatch) {
    previousItems.push({
      task: uncheckedMatch[1].trim(),
      completed: false,
      completedDate: null
    });
  } else if (checkedMatch) {
    previousItems.push({
      task: checkedMatch[1].trim(),
      completed: true,
      completedDate: checkedMatch[2] ? checkedMatch[2].trim() : currentDate
    });
  }
});

// New action items from today's analysis
const newItems = a.consolidatedActionItems || [];

// Check which previous items are resolved by new emails (stale items with recommendations)
const staleTaskTexts = (a.staleItems || []).map(s => s.task.toLowerCase());

// Mark previous uncompleted items as completed if they appear resolved
previousItems.forEach(item => {
  if (!item.completed) {
    // Check if any new email analysis suggests this is resolved
    const taskLower = item.task.toLowerCase();
    const isResolved = (a.emailAnalyses || []).some(e => {
      const summary = (e.summary || '').toLowerCase();
      const keywords = taskLower.split(/\s+/).filter(w => w.length > 3);
      return keywords.some(kw => summary.includes(kw)) && 
             (e.sentiment === 'positive' || summary.includes('completed') || summary.includes('done') || summary.includes('submitted'));
    });
    if (isResolved) {
      item.completed = true;
      item.completedDate = currentDate;
    }
  }
});

// Build the markdown file
let md = '# Active Action Items\n\n';

// Must Do Today section
md += `## Must Do Today (${currentDate})\n`;
const mustDoToday = newItems.filter(i => i.priority === 'must-do-today');
const prevMustDo = previousItems.filter(i => !i.completed && i.task.includes('must-do-today'));
if (mustDoToday.length > 0) {
  mustDoToday.forEach(item => {
    const deadline = item.deadline ? ` — Deadline: ${item.deadline}` : '';
    const source = item.sourceEmail ? ` — Source: ${item.sourceEmail}` : '';
    md += `- [ ] ${item.task}${deadline}${source}\n`;
  });
} else {
  md += '_No must-do-today items._\n';
}
md += '\n';

// This Week section
md += '## This Week\n';
const thisWeek = newItems.filter(i => i.priority === 'this-week');
const prevThisWeek = previousItems.filter(i => !i.completed && !i.task.includes('must-do-today'));
if (thisWeek.length > 0 || prevThisWeek.length > 0) {
  thisWeek.forEach(item => {
    const deadline = item.deadline ? ` — Deadline: ${item.deadline}` : '';
    const source = item.sourceEmail ? ` — Source: ${item.sourceEmail}` : '';
    md += `- [ ] ${item.task}${deadline}${source} (added ${currentDate})\n`;
  });
  // Carry forward previous unresolved this-week items
  prevThisWeek.forEach(item => {
    md += `- [ ] ${item.task}\n`;
  });
} else {
  md += '_No this-week items._\n';
}
md += '\n';

// When Possible section
const whenPossible = newItems.filter(i => i.priority === 'when-possible');
if (whenPossible.length > 0) {
  md += '## When Possible\n';
  whenPossible.forEach(item => {
    const deadline = item.deadline ? ` — Deadline: ${item.deadline}` : '';
    const source = item.sourceEmail ? ` — Source: ${item.sourceEmail}` : '';
    md += `- [ ] ${item.task}${deadline}${source} (added ${currentDate})\n`;
  });
  md += '\n';
}

// Completed section (last 7 days)
const completedItems = previousItems.filter(i => i.completed);
if (completedItems.length > 0) {
  md += '## Completed (last 7 days)\n';
  // Filter out items completed more than 7 days ago
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

  completedItems.forEach(item => {
    let keep = true;
    if (item.completedDate) {
      const completedDateObj = new Date(item.completedDate);
      if (completedDateObj < sevenDaysAgo) keep = false;
    }
    if (keep) {
      const dateStr = item.completedDate || currentDate;
      md += `- [x] ~~${item.task}~~ — Completed ${dateStr}\n`;
    }
  });
  md += '\n';
}

return [{
  json: {
    ...data,
    actionItemsMd: md
  }
}];

